pub const OSI_HIERARCHY_CONSTRAINT: &str =
    "Module at layer N can depend only on modules at layers 1..N";

/// Verification: lake build Gnosis.OSIComplete + cargo layer-check
pub const VERIFICATION_METHOD: &str =
    "Lean proof + static dependency analysis + runtime OSI tags";

/// Count of Rust modules with explicit OSI certification
