#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn witness_ids_are_correct() {
        assert_eq!(WITNESS_L1_GNOSIS_WASM.id, 106);
        assert_eq!(WITNESS_L7_GNOSIS.id, 700);
    }

    #[test]
    fn layers_are_in_range() {
        assert!(WITNESS_L1_GNOSIS_WASM.layer >= 1);
        assert!(WITNESS_L7_GNOSIS.layer <= 7);
    }
}
